import numpy as np
from scipy.optimize import least_squares
import csv, re
from pathlib import Path
import os

data_root = Path('/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited')
datasets = []
for dirpath, _, filenames in os.walk(data_root):
    if 'fit.tsv' in filenames:
        datasets.append(Path(dirpath) / 'fit.tsv')
datasets.sort()

def load_dataset(path):
    with open(path) as f:
        reader = csv.reader(f, delimiter='\t')
        header = next(reader)
        response_headers = header[1:]
        parsed = []
        for h in response_headers:
            m = re.search(r'(\d+(?:\.\d+)?)\s*uM', h, re.IGNORECASE)
            if m: parsed.append(float(m.group(1)))
            else: parsed.append(None)
        if all(p is not None for p in parsed):
            params = [float(p) for p in parsed]
        else:
            params = [float(i+1) for i in range(len(response_headers))]
        rows = list(reader)
        X, y = [], []
        for row in rows:
            if not row: continue
            x0 = float(row[0])
            for param, val in zip(params, row[1:]):
                if val and val.strip().lower() != 'nan':
                    X.append([x0, param])
                    y.append(float(val))
    return np.array(X), np.array(y)

def split(X, y):
    rng = np.random.default_rng(42)
    idx = rng.permutation(len(y))
    sp = int(round(len(y)*0.75))
    ti, vi = np.sort(idx[:sp]), np.sort(idx[sp:])
    return X[ti], X[vi], y[ti], y[vi]

# Model E: 5-param logistic with x1 in rate AND half-time separately
def modelE(th, X):
    c0,c1,c2,c3,c4 = th
    t,p = X[:,0],X[:,1]
    return c0/(1+np.exp(-c1*(t-c2-c3*p)))+c4

# Model F: Gompertz (asymmetric sigmoid) - better for aggregation
def modelF(th, X):
    c0,c1,c2,c3 = th
    t = X[:,0]
    return c0*np.exp(-np.exp(-c1*(t-c2)))+c3

# Model G: Hill function (power-law sigmoid)
def modelG(th, X):
    c0,c1,c2,c3 = th
    t = X[:,0]
    tn = np.abs(t)**np.clip(c2, 0.1, 10)
    c1n = np.abs(c1)**np.clip(c2, 0.1, 10)
    return c0*tn/(c1n+tn)+c3

# Model H: logistic with x1 shifting half-time (most natural for conc)
def modelH(th, X):
    c0,c1,c2,c3,c4 = th
    t,p = X[:,0],X[:,1]
    return c0/(1+np.exp(-c1*(t-c2/p)))+c3

models = [
    ('E_x1shift5c', modelE, [1.0,0.5,5.0,0.0,0.0], 5),
    ('F_gompertz4c', modelF, [1.0,0.5,5.0,0.0], 4),
    ('H_invx1half5c', modelH, [1.0,0.5,5.0,1.0,0.0], 5),
]

results = {name: [] for name,_,_,_ in models}
bad_datasets = {name: [] for name,_,_,_ in models}
for d in datasets:
    X, y = load_dataset(d)
    Xtr,Xval,ytr,yval = split(X,y)
    var = np.var(yval)
    for name, model, x0, nc in models:
        def res(th): return model(th, Xtr) - ytr
        try:
            r = least_squares(res, x0, loss='soft_l1', max_nfev=300)
            yp = model(r.x, Xval)
            nmse_v = np.mean((yval-yp)**2)/(var if var>1e-10 else 1)
        except:
            nmse_v = 10.0
        v = min(nmse_v, 10.0)
        results[name].append(v)
        if v > 1.0:
            bad_datasets[name].append(d.parent.name)

for name, vals in results.items():
    print(f'{name}: mean={np.mean(vals):.4f} >1: {sum(v>1 for v in vals)}')
    if bad_datasets[name]:
        print(f'  bad: {bad_datasets[name][:5]}')
